const periodo = $('start end 1').item.json;
const dias = Number(periodo.dias);

function subtrairDias(data, qtdDias) {
  const d = new Date(data);
  d.setDate(d.getDate() - qtdDias);

  return d.toISOString().slice(0, 10);
}

const [atualResp, anteriorResp] = $input.all().map(i => i.json);

const atual = atualResp.results;
const anterior = anteriorResp.results;

function variacao(atual, anterior) {
	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
		return null;
	}

	return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {

	atual = Number(atual);
	anterior = Number(anterior);

	if (!isFinite(atual) || !isFinite(anterior)) {
		return "➖";
	}

	const dif = atual - anterior;

	if (Math.abs(dif) <= tolerancia) {
		return "➖";
	}

	if (menorMelhor) {
		return dif < 0 ? "⬆️" : "⬇️";
	}

	return dif > 0 ? "⬆️" : "⬇️";
}

const campanhasAnteriores = {};

for (const campanha of anterior) {
	campanhasAnteriores[campanha.campaign.id] = campanha;
}

const resultado = {};

const totalAtual = {
	investimento: 0,
	impressoes: 0,
	cliques: 0,
	conversoes: 0,
	todas_conversoes: 0,
	valor_conversoes: 0,
	valor_todas_conversoes: 0
};

const totalAnterior = {
	investimento: 0,
	impressoes: 0,
	cliques: 0,
	conversoes: 0,
	todas_conversoes: 0,
	valor_conversoes: 0,
	valor_todas_conversoes: 0
};

for (const campanhaAtual of atual) {

	const campanhaAnterior = campanhasAnteriores[campanhaAtual.campaign.id];

	if (!campanhaAnterior) continue;

	const a = campanhaAtual.metrics;
	const b = campanhaAnterior.metrics;

    totalAtual.investimento += Number(a.costMicros) / 1e6;
    totalAtual.impressoes += Number(a.impressions);
    totalAtual.cliques += Number(a.clicks);
    totalAtual.conversoes += Number(a.conversions);
    totalAtual.todas_conversoes += Number(a.allConversions);
    totalAtual.valor_conversoes += Number(a.conversionsValue);
    totalAtual.valor_todas_conversoes += Number(a.allConversionsValue);

    totalAnterior.investimento += Number(b.costMicros) / 1e6;
    totalAnterior.impressoes += Number(b.impressions);
    totalAnterior.cliques += Number(b.clicks);
    totalAnterior.conversoes += Number(b.conversions);
    totalAnterior.todas_conversoes += Number(b.allConversions);
    totalAnterior.valor_conversoes += Number(b.conversionsValue);
    totalAnterior.valor_todas_conversoes += Number(b.allConversionsValue);

	const nome = campanhaAtual.campaign.name;

	resultado[nome] = {

		atual: {
            inicio: periodo.start_date,
            fim: periodo.end_date,

			id: campanhaAtual.campaign.id,
			nome,

			investimento: Number(a.costMicros) / 1e6,
			impressoes: Number(a.impressions),
			cpm: Number(a.averageCpm) / 1e6,
			ctr: Number(a.ctr) * 100,
			cliques: Number(a.clicks),
			cpc: Number(a.averageCpc) / 1e6,
			conversoes: Number(a.conversions),
            custo_por_lead: Number(a.conversions) > 0 ? (Number(a.costMicros) / 1e6) / Number(a.conversions) : 0,
			todas_conversoes: Number(a.allConversions),
			valor_conversoes: Number(a.conversionsValue),
			valor_todas_conversoes: Number(a.allConversionsValue)
		},

		anterior: {
            inicio: subtrairDias(periodo.start_date, dias),
            fim: subtrairDias(periodo.end_date, dias),

			id: campanhaAnterior.campaign.id,
			nome,

			investimento: Number(b.costMicros) / 1e6,
			impressoes: Number(b.impressions),
			cpm: Number(b.averageCpm) / 1e6,
			ctr: Number(b.ctr) * 100,
			cliques: Number(b.clicks),
			cpc: Number(b.averageCpc) / 1e6,
			conversoes: Number(b.conversions),
            custo_por_lead: Number(b.conversions) > 0 ? (Number(b.costMicros) / 1e6) / Number(b.conversions) : 0,
			todas_conversoes: Number(b.allConversions),
			valor_conversoes: Number(b.conversionsValue),
			valor_todas_conversoes: Number(b.allConversionsValue)

		},

		comparativo: {

			investimento: {
				variacao: variacao(Number(a.costMicros)/1e6, Number(b.costMicros)/1e6),
				icone: direcao(
					variacao(Number(a.costMicros)/1e6, Number(b.costMicros)/1e6),
					0,
					false,
					10
				)
			},

			impressoes: {
				variacao: variacao(a.impressions, b.impressions),
				icone: direcao(a.impressions, b.impressions)
			},

			cliques: {
				variacao: variacao(a.clicks, b.clicks),
				icone: direcao(a.clicks, b.clicks)
			},

			ctr: {
				variacao_pp: (Number(a.ctr) - Number(b.ctr)) * 100,
				icone: direcao(Number(a.ctr)*100, Number(b.ctr)*100, false, 0.5)
			},

			cpc: {
				variacao: variacao(Number(a.averageCpc), Number(b.averageCpc)),
				icone: direcao(
					variacao(Number(a.averageCpc), Number(b.averageCpc)),
					0,
					true,
					5
				)
			},

            custo_por_lead: {
                variacao: variacao(
                    Number(a.conversions) > 0
                        ? (Number(a.costMicros) / 1e6) / Number(a.conversions)
                        : 0,
                    Number(b.conversions) > 0
                        ? (Number(b.costMicros) / 1e6) / Number(b.conversions)
                        : 0
                ),
                icone: direcao(
                    Number(a.conversions) > 0
                        ? (Number(a.costMicros) / 1e6) / Number(a.conversions)
                        : 0,
                    Number(b.conversions) > 0
                        ? (Number(b.costMicros) / 1e6) / Number(b.conversions)
                        : 0,
                    true,
                    5
                )
            },

			cpm: {
				variacao: variacao(Number(a.averageCpm), Number(b.averageCpm)),
				icone: direcao(
					variacao(Number(a.averageCpm), Number(b.averageCpm)),
					0,
					true,
					5
				)
			},

			conversoes: {
				variacao: variacao(a.conversions, b.conversions),
				icone: direcao(a.conversions, b.conversions)
			},

			todas_conversoes: {
				variacao: variacao(a.allConversions, b.allConversions),
				icone: direcao(a.allConversions, b.allConversions)
			},

			valor_conversoes: {
				variacao: variacao(a.conversionsValue, b.conversionsValue),
				icone: direcao(a.conversionsValue, b.conversionsValue)
			},

			valor_todas_conversoes: {
				variacao: variacao(a.allConversionsValue, b.allConversionsValue),
				icone: direcao(a.allConversionsValue, b.allConversionsValue)
			}

		}

	};

}

return [
	{
		json: resultado
	}
];

const items = $input.all().map(i => i.json);

// Organiza por período e campanha
const dados = {};

for (const item of items) {
  if (!dados[item.periodo]) dados[item.periodo] = {};
  dados[item.periodo][item.campanha] = item;
}

function variacao(atual, anterior) {
  atual = Number(atual);
  anterior = Number(anterior);

  if (!isFinite(atual) || !isFinite(anterior) || anterior === 0) {
    return null;
  }

  return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {
  atual = Number(atual);
  anterior = Number(anterior);

  const dif = atual - anterior;

  if (Math.abs(dif) <= tolerancia) {
    return "➖";
  }

  if (menorMelhor) {
    return dif < 0 ? "⬆️" : "⬇️";
  }

  return dif > 0 ? "⬆️" : "⬇️";
}

function compararCampanha(nomeCampanha) {

  const atual = dados.atual[nomeCampanha];
  const anterior = dados.anterior[nomeCampanha];

  const resultado = {
    atual,
    anterior,
    comparativo: {

      investimento: {
        variacao: variacao(atual.investimento, anterior.investimento),
        icone: direcao(
          variacao(atual.investimento, anterior.investimento),
          0,
          false,
          10
        )
      },

      impressoes: {
        variacao: variacao(atual.impressoes, anterior.impressoes),
        icone: direcao(atual.impressoes, anterior.impressoes)
      },

      alcance: {
        variacao: variacao(atual.alcance, anterior.alcance),
        icone: direcao(atual.alcance, anterior.alcance)
      },

      cliques: {
        variacao: variacao(atual.cliques, anterior.cliques),
        icone: direcao(atual.cliques, anterior.cliques)
      },

      ctr: {
        variacao_pp: Number(atual.ctr) - Number(anterior.ctr),
        icone: direcao(atual.ctr, anterior.ctr, false, 0.20)
      },

      cpc: {
        variacao: variacao(atual.cpc, anterior.cpc),
        icone: direcao(
          variacao(atual.cpc, anterior.cpc),
          0,
          true,
          5
        )
      },

      landing_page_view: {
        variacao: variacao(
          atual.landing_page_view,
          anterior.landing_page_view
        ),
        icone: direcao(
          atual.landing_page_view,
          anterior.landing_page_view
        )
      },

      post_engagement: {
        variacao: variacao(
          atual.post_engagement,
          anterior.post_engagement
        ),
        icone: direcao(
          atual.post_engagement,
          anterior.post_engagement
        )
      }

    }
  };

  // Apenas CAPTURA possui métricas de funil
  if (nomeCampanha === "CAPTURA") {

    resultado.comparativo.contatos = {
      variacao: variacao(atual.contatos, anterior.contatos),
      icone: direcao(atual.contatos, anterior.contatos)
    };

    resultado.comparativo.conversao_funil = {
      variacao_pp:
        Number(atual.conversao_funil_pct) -
        Number(anterior.conversao_funil_pct),

      icone: direcao(
        atual.conversao_funil_pct,
        anterior.conversao_funil_pct,
        false,
        2
      )
    };

    resultado.comparativo.custo_por_contato = {
      variacao: variacao(
        atual.custo_por_contato,
        anterior.custo_por_contato
      ),

      icone: direcao(
        variacao(
          atual.custo_por_contato,
          anterior.custo_por_contato
        ),
        0,
        true,
        5
      )
    };

  }

  return resultado;
}

return [
  {
    json: {
      CAPTURA: compararCampanha("CAPTURA"),
      DISTRIBUICAO: compararCampanha("DISTRIBUICAO")
    }
  }
];

